 'unset', // Prevent element from shaking after drag\n};\nconst DraggableTag = props => {\n  const { tag } = props;\n  const { listeners, transform, transition, isDragging, setNodeRef } = useSortable({ id: tag.id });\n  const style = transform\n    ? {\n        ...commonStyle,\n        transform: `translate3d(${transform.x}px, ${transform.y}px, 0)`,\n        transition: isDragging ? 'unset' : transition, // Improve performance/visual effect when dragging\n      }\n    : commonStyle;\n  return (\n    <Tag style={style} ref={setNodeRef} {...listeners}>\n      {tag.text}\n    </Tag>\n  );\n};\nconst App = () => {\n  const [items, setItems] = useState([\n    { id: 1, text: 'Tag 1' },\n    { id: 2, text: 'Tag 2' },\n    { id: 3, text: 'Tag 3' },\n  ]);\n  const sensors = useSensors(useSensor(PointerSensor));\n  const handleDragEnd = event => {\n    const { active, over } = event;\n    if (!over) {\n      return;\n    }\n    if (active.id !== over.id) {\n      setItems(data => {\n        const oldIndex = data.findIndex(item => item.id === active.id);\n        const newIndex = data.findIndex(item => item.id === over.id);\n        return arrayMove(data, oldIndex, newIndex);\n      });\n    }\n  };\n  return (\n    <DndContext sensors={sensors} onDragEnd={handleDragEnd} collisionDetection={closestCenter}>\n      <SortableContext items={items} strategy={horizontalListSortingStrategy}>\n        <Flex gap=\"small\" align=\"center\" wrap>\n          {items.map(item => (\n            <DraggableTag tag={item} key={item.id} />\n          ))}\n        </Flex>\n      </SortableContext>\n    </DndContext>\n  );\n};\nexport default App;\n",description:'<p>使用 <a href="https://dndkit.com">dnd kit</a> 实现的可拖拽标签。</p>'}},{demo:{id:"tag-demo-component-token",loader:()=>e.A(362162),version:"643c3d65"},previewerProps:{debug:!0,title:"组件 Token",filename:"components/tag/demo/component-token.tsx",pkgDependencyList:{"@ant-design/compatible":"^5.1.4","@ant-design/happy-work-theme":"^2.0.0","@ant-des